const input = $input.item.json.chatInput || '';
const goal = input.trim();
if (!goal || goal.length < 5) {
  return { json: { valid: false, goal: '', error: 'Please describe your goal. Example: Launch my SaaS product in 30 days' } };
}
let goalType = 'general';
const lower = goal.toLowerCase();
if (lower.match(/launch|build|create|develop|start/)) goalType = 'creation';
else if (lower.match(/learn|study|master/)) goalType = 'learning';
else if (lower.match(/grow|scale|increase|improve/)) goalType = 'growth';
else if (lower.match(/plan|organize|manage/)) goalType = 'planning';
else if (lower.match(/market|promote|sell/)) goalType = 'marketing';
let timeframe = '30 days';
const tm = goal.match(/(\d+)\s*(day|week|month|hour)/i);
if (tm) timeframe = tm[0];
return { json: { valid: true, goal: goal, goalType: goalType, timeframe: timeframe, sessionId: 'task_' + Date.now() } };

const analysis = $input.item.json.text || '';
const prev = $('Goal Input Processor').item.json;
return { json: { goal: prev.goal, goalType: prev.goalType, timeframe: prev.timeframe, sessionId: prev.sessionId, goalAnalysis: analysis } };

const tasks = $input.item.json.text || '';
const prev = $('Store Goal Analysis').item.json;
return { json: { goal: prev.goal, goalType: prev.goalType, timeframe: prev.timeframe, sessionId: prev.sessionId, goalAnalysis: prev.goalAnalysis, taskBreakdown: tasks } };

const plan = $input.item.json.text || '';
const prev = $('Store Task Breakdown').item.json;
return { json: { goal: prev.goal, goalType: prev.goalType, timeframe: prev.timeframe, sessionId: prev.sessionId, goalAnalysis: prev.goalAnalysis, taskBreakdown: prev.taskBreakdown, priorityPlan: plan } };

const execution = $input.item.json.text || '';
const prev = $('Store Priority Plan').item.json;
return { json: { goal: prev.goal, goalType: prev.goalType, timeframe: prev.timeframe, sessionId: prev.sessionId, goalAnalysis: prev.goalAnalysis, taskBreakdown: prev.taskBreakdown, priorityPlan: prev.priorityPlan, executionGuide: execution } };
